-- 1. Chatham × Web Design
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'web-design',
  'chatham',
  'Chatham is a town undergoing serious reinvention. The regeneration around Chatham Maritime and the Historic Dockyard has brought new restaurants, residential developments, and a growing student population from the Universities at Medway campus. Meanwhile, the established commercial heart around the Pentagon Shopping Centre and the High Street continues to serve a population of roughly eighty thousand across the town and a wider Medway area approaching two hundred and eighty thousand. This is a market with scale, ambition, and increasing digital expectations. Students, young professionals in the Maritime quarter, and families across the residential areas all judge businesses by their online presence first. We build bespoke, conversion-focused websites for Chatham businesses that match the energy of a town in transformation, turning search visitors into genuine paying customers across the entire Medway catchment.',
  'Chatham sits at the commercial centre of the Medway Towns, connected by the A2 and M2 to London and the wider Kent motorway network. The Historic Dockyard draws heritage tourists and event visitors year-round, while Chatham Maritime provides a modern dining, leisure, and residential destination. The Pentagon Shopping Centre anchors the town centre retail offering. The Universities at Medway campus, shared between three universities, brings thousands of students who live and spend locally. Fort Amherst adds another heritage attraction. Chatham railway station provides direct services into London, and the wider Medway area encompasses Rochester, Gillingham, Strood, and Rainham, creating a substantial combined market.',
  'The web design market serving Chatham is split between larger Medway-based agencies targeting the whole region and budget freelancers competing on price. Many established businesses around the Pentagon and High Street still operate websites built years ago that fail mobile usability standards. The Maritime quarter has attracted newer businesses with more modern digital presence, creating a visible divide between old Chatham and the regenerated areas. National franchises with professional sites further raise the bar that local independent businesses are judged against.',
  'Our approach for Chatham clients recognises that the real market extends across the entire Medway Towns. A website for a Chatham business needs to attract customers from Rochester, Gillingham, Rainham, and Strood, not just the immediate High Street area. We build sites with Medway-wide SEO architecture, mobile-first design for the student and young professional demographic, and conversion paths tailored to each customer segment within this diverse market.',
  '{"population": 80000, "growth": "Significant regeneration around Maritime quarter and Dockyard", "business_districts": ["Pentagon Shopping Centre", "High Street", "Chatham Maritime", "Historic Dockyard area"], "key_fact": "Central hub of Medway Towns with combined catchment approaching 280,000"}',
  '[{"title": "Outdated websites failing Chatham''s regenerating image", "description": "As Chatham Maritime attracts modern restaurants and the Dockyard draws visitors, businesses around the Pentagon and High Street with dated websites look increasingly out of step with the town''s transformation. The visual gap between old and new Chatham extends online, where outdated sites suggest a business that has not kept pace with the town''s evolution."}, {"title": "Missing the Medway-wide market from a Chatham base", "description": "A Chatham business with a website that only references the town misses customers in Rochester, Gillingham, Strood, and Rainham. The Medway Towns function as a single economic area approaching two hundred and eighty thousand people, but most Chatham business websites are built as if the market ends at the town boundary."}, {"title": "Student and young professional expectations unmet", "description": "The Universities at Medway campus brings thousands of students who live in and around Chatham. These digital natives judge every business by its website before visiting. A site that loads slowly, looks dated, or lacks online booking sends them straight to a competitor with a more polished digital experience."}]',
  '[{"title": "Websites built for the new Chatham", "description": "We design sites that reflect the energy of Chatham''s regeneration. Modern, fast, and conversion-focused, matching the standards set by the Maritime quarter and appealing to the student population, young professionals, and established Medway residents alike. Your website should match the ambition of the town around it."}, {"title": "Medway-wide SEO architecture from launch", "description": "Every Chatham site we build includes service and area pages targeting Rochester, Gillingham, Strood, Rainham, and the wider Medway area. This structural SEO approach ensures your Chatham business captures customers from across the entire Medway catchment, not just visitors who already know your name."}, {"title": "Mobile-first design for Chatham''s digital-first audience", "description": "With a large student population and growing young professional demographic, Chatham demands mobile-first web design. Sub-two-second load times, intuitive mobile navigation, and prominent conversion elements ensure your site performs for the audience that matters most to your growth."}]',
  '[{"question": "How long does a new website take for a Chatham business?", "answer": "Most Chatham projects launch within four to six weeks. We begin with a strategy session understanding your position in the Medway market, your target customers across the towns, and your competitive landscape. Design, development, and testing follow a structured timeline with clear milestones."}, {"question": "Will my site attract customers from across Medway, not just Chatham?", "answer": "Yes. We build Medway-wide SEO into every site from the start. Area-specific pages targeting Rochester, Gillingham, Strood, and Rainham ensure your Chatham business appears in searches across the entire combined market of nearly two hundred and eighty thousand people."}, {"question": "Do you design for businesses in the Chatham Maritime area?", "answer": "Yes. We work with businesses across all areas of Chatham including the Maritime quarter, the Historic Dockyard vicinity, the Pentagon and High Street, and the residential areas. Each location has different customer profiles, and we tailor the design and content accordingly."}, {"question": "Can you redesign my existing Chatham business website?", "answer": "Absolutely. We audit your current site, preserve any search authority through proper redirects, and deliver a modern redesign that matches the standards of Chatham''s regenerated commercial landscape. Most redesigns launch within four to six weeks."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
