-- 6. Chatham × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'chatham',
  'Social media in Chatham reaches far beyond the town itself. With nearly two hundred and eighty thousand people across the Medway Towns using Facebook, Instagram, and TikTok daily, a well-set-up Chatham business social presence can attract customers from Rochester, Gillingham, Strood, and Rainham without spending a penny on advertising. The Universities at Medway campus alone brings thousands of young people who discover businesses entirely through social media rather than search engines. The Maritime quarter restaurants that fill their tables through Instagram prove what is possible when social media is set up strategically rather than sporadically. Yet the majority of Chatham businesses have dormant Facebook pages, no Instagram presence, and no content strategy connecting them to the wider Medway audience. We set up professional social media foundations that position Chatham businesses to reach the full Medway market from day one.',
  'Chatham''s social media landscape benefits from the concentrated Medway population and the variety of content opportunities the town provides. The Historic Dockyard and Fort Amherst generate heritage and tourism content. The Maritime quarter provides a photogenic modern backdrop for hospitality and lifestyle posts. The Pentagon Shopping Centre creates retail and community content opportunities. The Brook Theatre and local events provide regular content hooks. The Universities at Medway student community is highly active on social media, creating organic engagement opportunities for businesses that position themselves correctly.',
  'Social media quality among Chatham businesses is polarised. Maritime quarter restaurants and newer businesses tend to have active, visually appealing profiles that generate genuine engagement. Established businesses around the Pentagon and High Street typically have outdated Facebook pages with irregular posting and no visual consistency. The gap between social media leaders and laggards in Chatham is widening, with professionally managed profiles absorbing the engagement that poorly maintained ones forfeit.',
  'We set up Chatham social profiles with Medway-wide reach built in from the start. Profile optimisation targets the combined Medway audience. Content pillars are structured around the different communities within the towns. Hashtag strategies leverage location-specific tags for Chatham, Rochester, Gillingham, and Medway. Brand-consistent templates ensure visual quality regardless of who posts. A strategic foundation means every post contributes to growing your Medway-wide audience.',
  '{"population": 80000, "growth": "Growing social media audience through student and young professional demographics", "business_districts": ["Chatham Maritime", "Pentagon Shopping Centre", "High Street", "Universities at Medway"], "key_fact": "University student population highly active on social media, creating organic engagement opportunities"}',
  '[{"title": "Dormant Chatham social profiles losing Medway customers", "description": "A potential customer searches for your Chatham business on Facebook and finds a page last updated four months ago with a blurry cover photo. They immediately question whether the business is still operating. In a market of two hundred and eighty thousand people, dormant social media does not just miss opportunities, it actively drives customers away."}, {"title": "No Medway-wide social media strategy from Chatham base", "description": "Chatham businesses posting only to their immediate local followers miss the vast majority of the Medway social media audience. Without hashtag strategies, location tagging, and content themes that resonate across Rochester, Gillingham, Strood, and Rainham, social media reach stays limited to existing connections."}, {"title": "Missing the student social media audience entirely", "description": "Universities at Medway students discover local businesses almost exclusively through social media. They search Instagram and TikTok, not Google. Chatham businesses without active, visually appealing profiles on these platforms are invisible to thousands of potential customers living minutes away from their door."}]',
  '[{"title": "Medway-wide social media setup for Chatham businesses", "description": "We configure your social profiles to reach the entire Medway market, not just Chatham. Optimised bios referencing your service areas, location-tagged content strategies, and Medway-wide hashtag usage ensure every post reaches potential customers across all five towns from a Chatham base."}, {"title": "Platform-specific setup for Chatham''s diverse audiences", "description": "Facebook for the established Medway community. Instagram for the Maritime quarter and hospitality audience. TikTok for the student demographic. We set up each platform with the right profile, content structure, and visual identity to resonate with the specific audience that uses it."}, {"title": "Brand-consistent templates for professional posting", "description": "We create a library of branded social media templates that anyone on your team can use. Consistent visual identity across every post reinforces your professional credibility and makes your Chatham business instantly recognisable in the busy feeds of Medway''s social media audience."}]',
  '[{"question": "Which social media platforms work best for Chatham businesses?", "answer": "Facebook remains the strongest platform for reaching the established Medway community. Instagram performs well for hospitality, retail, and lifestyle businesses, particularly those in the Maritime quarter. TikTok is increasingly important for reaching the university student demographic. We recommend the combination that matches your specific audience."}, {"question": "Can social media really reach customers across all of Medway?", "answer": "Yes. With proper setup including location tagging, area-specific hashtags, and content that resonates across the towns, a Chatham-based social presence routinely reaches audiences in Rochester, Gillingham, Strood, and Rainham. The Medway Towns function as a single social media market when your profiles are configured correctly."}, {"question": "How do you set up social media for a new Chatham business?", "answer": "We build profiles from scratch across the relevant platforms, including brand-consistent visuals, optimised bios, content pillars, and a launch content plan. For new Chatham businesses, we also develop a follower growth strategy targeting the specific Medway audiences most likely to become customers."}, {"question": "Do you manage social media ongoing or just set it up?", "answer": "This service focuses on professional setup and strategic foundations. We deliver fully configured profiles, content calendars, branded templates, and posting guidelines that enable you or your team to maintain a consistent, effective presence. Ongoing management is available as a separate service if needed."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
